387	function useFloatingCta(
388	  phoneRef: React.RefObject<HTMLDivElement | null>,
389	): boolean {
390	  const [floating, setFloating] = useState(false);
391	
392	  useEffect(() => {
393	    const phone = phoneRef.current;
394	    if (!phone) return;
395	
396	    const update = (): void => {
397	      const phoneRect = phone.getBoundingClientRect();
398	      const vh = window.innerHeight;
399	      // Threshold is tuned so the floating button and its static-flow slot
400	      // line up vertically at the moment of switch — the visual position
401	      // doesn't jump.
402	      const phoneEnoughVisible = phoneRect.top < vh - 200;
403	      // The floating button sits at vh - 56 (bottom-6 + button height). The
404	      // static slot sits at phoneRect.bottom + 62 (flex gap-8 + pt-2 + half
405	      // button). The switch happens when the two y positions match.
406	      const phoneStillNearBottom = phoneRect.bottom > vh - 118;
407	      setFloating(phoneEnoughVisible && phoneStillNearBottom);
408	    };
409	
410	    update();
411	    window.addEventListener("scroll", update, { passive: true });
412	    window.addEventListener("resize", update);
413	    return () => {
414	      window.removeEventListener("scroll", update);
415	      window.removeEventListener("resize", update);
416	    };
417	  }, [phoneRef]);
