425	function useStaggeredMessages(platform: Platform): ChatMessageItem[] {
426	  const allMessages = platform.demo.messages;
427	  const [visibleCount, setVisibleCount] = useState(1);
428	  const [showTyping, setShowTyping] = useState(false);
429	
430	  useEffect(() => {
431	    setVisibleCount(1);
432	    setShowTyping(false);
433	    if (allMessages.length <= 1) return;
434	
435	    const timers: ReturnType<typeof setTimeout>[] = [];
436	    let elapsed = 0;
437	    for (let i = 1; i < allMessages.length; i++) {
438	      elapsed += TYPING_DELAY_MS;
439	      timers.push(setTimeout(() => setShowTyping(true), elapsed));
440	      elapsed += TYPING_DURATION_MS;
441	      timers.push(
442	        setTimeout(() => {
443	          setShowTyping(false);
444	          setVisibleCount((c) => c + 1);
445	        }, elapsed),
446	      );
447	    }
448	
449	    return () => {
450	      for (const t of timers) clearTimeout(t);
451	    };
452	  }, [allMessages]);
453	
454	  return useMemo(() => {
455	    const real = allMessages.slice(0, visibleCount).map((m, i) => ({
456	      ...m,
457	      id: m.id ?? `msg-${i}`,
458	    }));
459	    if (!showTyping || visibleCount >= allMessages.length) return real;
460	    const next = allMessages[visibleCount];
461	    return [
462	      ...real,
463	      {
464	        id: `typing-${visibleCount}`,
465	        from: next.from,
466	        author: next.author,
467	        avatar: next.avatar,
468	        authorColor: next.authorColor,
469	        typing: true,
470	      },
471	    ];
472	  }, [allMessages, visibleCount, showTyping]);
473	}
